operation.add:
$cyberpunks_shop_head_includes_exclude = $this->registry->has('cyberpunks_shop_head_includes_exclude') ? $this->registry->get('cyberpunks_shop_head_includes_exclude') : array();
if (is_array($cyberpunks_shop_head_includes_exclude)) {
	if (!empty($cyberpunks_shop_head_includes_exclude['css']) && is_array($cyberpunks_shop_head_includes_exclude['css']) && is_array($data['styles'])) {
		foreach ($cyberpunks_shop_head_includes_exclude['css'] as $css_exclude_path) {
			if (isset($data['styles'][$css_exclude_path])) {
				unset($data['styles'][$css_exclude_path]);
			}
		}
	}

	if (!empty($cyberpunks_shop_head_includes_exclude['js']) && is_array($cyberpunks_shop_head_includes_exclude['js']) && is_array($data['scripts'])) {
		$data['scripts'] = array_values(array_filter($data['scripts'], function($script) use ($cyberpunks_shop_head_includes_exclude) {
			return !isset($cyberpunks_shop_head_includes_exclude['js'][$script]);
		}));
	}
}
